package main

import (
	"encoding/json"
	"os"
	"reflect"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func fieldsMatch(a, b entry) bool {
	return a.Case == b.Case &&
		reflect.DeepEqual(a.Produced, b.Produced) &&
		reflect.DeepEqual(a.Trace, b.Trace) &&
		reflect.DeepEqual(a.OrderUsed, b.OrderUsed) &&
		a.Packed == b.Packed &&
		a.Grouped == b.Grouped &&
		a.Reuse == b.Reuse
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	buf, err := os.ReadFile(os.Args[1])
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// Build new report rows from raw (preserve order, copy 6 fields)
	rows := make([]entry, len(raw.Raw))
	for i, r := range raw.Raw {
		rows[i] = entry{
			Case:      r.Case,
			Produced:  r.Produced,
			Trace:     r.Trace,
			OrderUsed: r.OrderUsed,
			Packed:    r.Packed,
			Grouped:   r.Grouped,
			Reuse:     r.Reuse,
		}
	}

	agree := true

	// If existing report.json exists, compare its rows against incoming raw
	if oldBuf, err := os.ReadFile(os.Args[2]); err == nil {
		var oldDoc finalDoc
		if err := json.Unmarshal(oldBuf, &oldDoc); err == nil {
			// Build map of old report rows by case name
			oldMap := make(map[string]entry)
			for _, r := range oldDoc.Rows {
				oldMap[r.Case] = r
			}
			if len(oldDoc.Rows) != len(raw.Raw) {
				agree = false
			} else {
				for _, r := range raw.Raw {
					oldRow, ok := oldMap[r.Case]
					if !ok || !fieldsMatch(oldRow, entry{
						Case:      r.Case,
						Produced:  r.Produced,
						Trace:     r.Trace,
						OrderUsed: r.OrderUsed,
						Packed:    r.Packed,
						Grouped:   r.Grouped,
						Reuse:     r.Reuse,
					}) {
						agree = false
						break
					}
				}
			}
		} else {
			agree = false
		}
	}
	// If no old report exists, agree stays true (new rows match raw by construction)

	doc := finalDoc{
		Rows:    rows,
		Summary: map[string]any{"total": len(rows), "agree": agree},
	}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(os.Args[2], append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
EOF
